#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5,M=450;

int n,q,a[N],cnt[M][N],len,t[4*N];

int cal(int x){
    return (x-1)/len+1;
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}

void modify(int cur,int l,int r,int x,int k){
    if(l==r){
        t[cur]=k;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,k);
    else
        modify(cur*2+1,mid+1,r,x,k);
    t[cur]=max(t[cur*2],t[cur*2+1]);
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,ans=0;
    if(x<=mid)
        ans=max(ans,query(cur*2,l,mid,x,y));
    if(y>mid)
        ans=max(ans,query(cur*2+1,mid+1,r,x,y));
    return ans;
}

void replace(int x,int y){
    cnt[cal(x)][a[x]]--;
    cnt[cal(x)][y]++;
    a[x]=y;
}

int ask(int l,int r,int mx){
    int p=cal(l),q=cal(r);
    int res=0;
    if(p==q){
        for(int i=l;i<=r;i++)
            res+=min(4,mx-a[i]);
    }else{
        for(int i=l;cal(i)==p;i++)
            res+=min(4,mx-a[i]);
        for(int i=r;cal(i)==q;i--)
            res+=min(4,mx-a[i]);
        for(int i=p+1;i<q;i++){
            res+=cnt[i][max(0,mx-1)];
            res+=cnt[i][max(0,mx-2)]*2;
            res+=cnt[i][max(0,mx-3)]*3;
            res+=(len-cnt[i][mx]-cnt[i][max(0,mx-1)]-cnt[i][max(0,mx-2)]-cnt[i][max(0,mx-3)])*4;
        }
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&q);
    len=sqrt(n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        cnt[cal(i)][a[i]]++;
    }
    build(1,1,n);
    while(q--){
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
            replace(x,y),modify(1,1,n,x,y);
        else
            printf("%d\n",ask(x,y,query(1,1,n,x,y)));
    }
    return 0;
}
